sql:
SELECT action_type, AVG(avg_action_dist) AS avg_distribution
FROM action_distributions
GROUP BY action_type;

SELECT access_date
FROM experiment_access
WHERE access_id = 0;

SELECT result_type, COUNT(DISTINCT experiment_id) AS distinct_experiment_count
     FROM experiment_results
     GROUP BY result_type;

external_knowledge:
- 'Comprehensive details' refers to the combination of experiment information, rewards, actions, and user access data; 
- 'Average rewards' and 'action distributions' are performance metrics for experiments; 
- 'User access history' includes access counts and dates.

sql:
SELECT experiment_id, COUNT(*) as note_count
FROM experiment_notes
GROUP BY experiment_id;

SELECT observation_type, COUNT(*) AS total_observations
FROM human_observations
GROUP BY observation_type;

SELECT version_number
FROM code_versions
WHERE experiment_id = 1;
